    "id": "https://agenciabrasil.ebc.com.br/cultura/noticia/2026-04/samba-da-gamboa-recebe-o-cantor-e-compositor-dudu-nobre-neste-domingo",
    "slug": "samba-da-gamboa-recebe-o-cantor-e-compositor-dudu-nobre-neste-domingo",
    "title": "Samba da Gamboa recebe o cantor e compositor Dudu Nobre neste domingo",
    "eyebrow": "cultura",
    "date": "25 de abr. de 2026",
    "publishedAt": "2026-04-25T17:00:00.000Z",
