    "title": "Usina de Chernobyl continua ameaçada mesmo após 40 anos do desastre nuclear",
    "eyebrow": "politica",
    "date": "26 de abr. de 2026",
    "publishedAt": "2026-04-26T07:00:15.000Z",
    "category": "Política",
    "categoryKey": "politica",
